define i1 @scalable(<vscale x 4 x i8> %v) {
  %red = call i8 @llvm.vector.reduce.and.nxv4i8(<vscale x 4 x i8> %v)
  %cmp = icmp eq i8 %red, -1
  ret i1 %cmp
}

